785:   always_comb begin : p_plic_if
786:     automatic logic [31:0] waddr, raddr;
787:     // subtract the base offset (truncated to 32 bits)
788:     waddr = plic_master.aw_addr[31:0] - 32'(PlicBase) + 32'hc000000;
789:     raddr = plic_master.ar_addr[31:0] - 32'(PlicBase) + 32'hc000000;
790: 
791:     // AXI-lite
792:     plic_master.aw_ready = plic_resp.ready;
793:     plic_master.w_ready  = plic_resp.ready;
794:     plic_master.ar_ready = plic_resp.ready;
795: 
796:     plic_master.r_valid  = 1'b0;
797:     plic_master.r_resp   = '0;
798:     plic_master.b_valid  = 1'b0;
799:     plic_master.b_resp   = '0;
800: 
801:     // PLIC
802:     plic_req.valid       = 1'b0;
803:     plic_req.wstrb       = '0;
804:     plic_req.write       = 1'b0;
805:     plic_req.wdata       = plic_master.w_data[31:0];
806:     plic_req.addr        = waddr;
807: 
808:     // default
809:     state_d              = state_q;
810: 
811:     unique case (state_q)
812:       Idle: begin
813:         if (plic_master.w_valid && plic_master.aw_valid && plic_resp.ready) begin
814:           plic_req.valid = 1'b1;
815:           plic_req.write = plic_master.w_strb[3:0];
816:           plic_req.wstrb = '1;
817:           // this is a 64bit write, need to write second 32bit chunk in second cycle
818:           if (plic_master.aw_size == 3'b11) begin
819:             state_d = WriteSecond;
820:           end else begin
821:             state_d = WriteResp;
822:           end
823:         end else if (plic_master.ar_valid && plic_resp.ready) begin
824:           plic_req.valid = 1'b1;
825:           plic_req.addr  = raddr;
826:           // this is a 64bit read, need to read second 32bit chunk in second cycle
827:           if (plic_master.ar_size == 3'b11) begin
828:             state_d = ReadSecond;
829:           end else begin
830:             state_d = ReadResp;
831:           end
832:         end
833:       end
834:       // write high word
835:       WriteSecond: begin
836:         plic_master.aw_ready = 1'b0;
837:         plic_master.w_ready  = 1'b0;
838:         plic_master.ar_ready = 1'b0;
839:         plic_req.addr        = waddr + 32'h4;
840:         plic_req.wdata       = plic_master.w_data[63:32];
841:         if (plic_resp.ready && plic_master.b_ready) begin
842:           plic_req.valid       = 1'b1;
843:           plic_req.write       = 1'b1;
844:           plic_req.wstrb       = '1;
845:           plic_master.b_valid  = 1'b1;
846:           state_d              = Idle;
847:         end
848:       end
849:       // read high word
850:       ReadSecond: begin
851:         plic_master.aw_ready = 1'b0;
852:         plic_master.w_ready  = 1'b0;
853:         plic_master.ar_ready = 1'b0;
854:         plic_req.addr        = raddr + 32'h4;
855:         if (plic_resp.ready && plic_master.r_ready) begin
856:           plic_req.valid      = 1'b1;
857:           plic_master.r_valid = 1'b1;
858:           state_d             = Idle;
859:         end
860:       end
861:       WriteResp: begin
862:         plic_master.aw_ready = 1'b0;
863:         plic_master.w_ready  = 1'b0;
864:         plic_master.ar_ready = 1'b0;
865:         if (plic_master.b_ready) begin
866:           plic_master.b_valid  = 1'b1;
867:           state_d              = Idle;
868:         end
869:       end
870:       ReadResp: begin
871:         plic_master.aw_ready = 1'b0;
872:         plic_master.w_ready  = 1'b0;
873:         plic_master.ar_ready = 1'b0;
874:         if (plic_master.r_ready) begin
875:           plic_master.r_valid = 1'b1;
876:           state_d             = Idle;
877:         end
878:       end
879:       default: state_d = Idle;
880:     endcase
